private static byte isNextVowel(String word) {
        if (word.length() == 0) {
            return -1;
        }
        char first = word.charAt(0);
        if (first == 'a' || first == 'e' || first == 'i' || first == 'o' || first == 'u') {
            return 1;
        }
        if (first == 'y') {
            return 2;
        }
        return 0;
    }

