prediction:
private boolean isOnCooldown(ItemStack item, LastEaten lastEaten) {
            final long cooldown = getCooldownForItem(item);
            final Optional<Instant> newestEatTime = lastEaten.getNewestEatTime();
            if (newestEatTime.isPresent()) {
                final Instant newestEat = newestEatTime.get();
                final Instant now = Instant.now();
                final long secondsSinceEat = ChronoUnit.SECONDS.between(newestEat, now);
                return secondsSinceEat < cooldown;
            }
            return false;
        }

