private IonCloud parseCharges(String str_charges) {
		IonCloud ion_cloud = new IonCloud("Na");
		if (str_charges.length() == 0)
			return ion_cloud;

		String[] tokens = TextUtils.tokenize(str_charges, ",");
		for (String token : tokens) {
			String[] tokens2 = TextUtils.tokenize(token, "-");
			if (tokens2.length == 2) {
				int charge = Integer.valueOf(tokens2[0]);
				String symbol = tokens2[1];
				ion_cloud.addCharge(symbol, charge);
			} else if (tokens2.length == 1) {
				String symbol = tokens2[0];
				ion_cloud.addCharge(symbol, 1);
			}
		}

		return ion_cloud;
	}

