private static int getHeight(Client client, int x, int y, int plane)
	{
		if (plane < 0 || plane >= Constants.MAX_Z)
		{
			return 0;
		}

		final int sceneX = client.getPlane() == plane? x : client.getLocalPlayer().getWorldLocation().getSceneX();
		final int sceneY = client.getPlane() == plane? y : client.getLocalPlayer().getWorldLocation().getSceneY();

		if (sceneX < 0 || sceneY < 0 || sceneX >= Perspective.SCENE_SIZE || sceneY >= Perspective.SCENE_SIZE)
		{
			return 0;
		}

		return client.getPlane() == plane? client.getPlaneHeight(x, y) : client.getPlaneHeight(sceneX, sceneY);
	}

