public static double OmegaF(double q, double F, double omega1) {
	double term = (q*q)/(2*(1+q));

	return ((omega1 + term)/F) - term;
    }

prediction:
public static double OmegaF(double q, double F, double omega1) {
	double potential;
	double expression;
	double denominator;

	denominator = Math.sqrt(1 - (2*F*Math.cos(omega1)) + (F*F));
	expression = (1/denominator) - (F*Math.cos(omega1));
	potential = (1/F) + q*(expression);
	return potential;
    }

