						 // tx2xフォルダの処理
						 Tx2xOptions.getInstance().setOption("tx2x_folder_file_name", file.getAbsolutePath());
						 IgnoreFile cIgnoreFile = IgnoreFile.getInstance();
						 cIgnoreFile.setIgnoreFiles(new File(file.getAbsolutePath() + File.separator + "tx2x.ignore"));
					 }
				 } else {
					 // ファイルの処理
					 if (file.getName().equals("tx2x.ignore")) {
						 // tx2x.ignoreの処理
						 Tx2xOptions.getInstance().setOption("tx2x_folder_file_name", file.getParentFile().getAbsolutePath());
