void loadConditions(DefaultComboBoxModel<Condition> filterConditionModel,
			String pathToFilterFile) throws IOException {
		XMLElement loader = new XMLElement();
		Reader reader = new FileReader(pathToFilterFile);
		loader.read(reader);
		reader.close();
		for (int i = 0; i < loader.getChildCount(); i++) {
			XMLElement cond = (XMLElement) loader.getChildAt(i);
			Condition newCond = ConditionFactory.createCondition(cond);
			filterConditionModel.addElement(newCond);
		}
	}

