private InputStream openZipStreamAt(URL url, String ext)
        throws IOException {
        InputStream stream = null;
        ZipInputStream zis = null;
        try {
            zis = new ZipInputStream(url.openStream());
            ZipEntry entry = null;
            while ((entry = zis.getNextEntry())!= null) {
                if (entry.getName().endsWith(ext)) {
                    stream = zis;
                    break;
                }
            }
        } finally {
            if (zis!= null) {
                zis.close();
            }
        }
        return stream;
    }

